mapper.select:
SELECT 
FROM cutover_plan cp


    cp.deleted = 0

        AND cp.project_id = #{query.projectId}


        AND cp.plan_name LIKE CONCAT('%', #{query.planName}, '%')


        AND cp.status = #{query.status}


        AND cp.cutover_date >= #{query.dateFrom}


        AND cp.cutover_date <= #{query.dateTo}


        AND cp.apply_user_id = #{query.applyUserId}


ORDER BY cp.create_time DESC
